/**
 * Self-contained Font Awesome 6 CSS with base64-embedded font files.
 *
 * In a production build, reads the pre-compiled fa-inline.css generated by
 * scripts/compile-fa.js (postinstall hook). In development, falls back to
 * generating from node_modules/@fortawesome/fontawesome-free on demand.
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const inlinePath = path.join(__dirname, "fa-inline.css");

let cachedCSS = null;

export function getFontAwesomeCSS() {
  if (cachedCSS) return cachedCSS;

  // Pre-compiled file exists (production build)
  if (fs.existsSync(inlinePath)) {
    cachedCSS = fs.readFileSync(inlinePath, "utf-8");
    return cachedCSS;
  }

  // Fall back to on-demand generation from node_modules (dev mode)
  cachedCSS = buildFromNodeModules();
  return cachedCSS;
}

function buildFromNodeModules() {
  const faRoot = path.resolve(__dirname, "..", "..", "node_modules", "@fortawesome", "fontawesome-free");
  const cssPath = path.join(faRoot, "css", "all.min.css");

  if (!fs.existsSync(cssPath)) {
    throw new Error(
      "Font Awesome not found. Run `npm install` (dev) or `npm run build` (production) first.",
    );
  }

  let css = fs.readFileSync(cssPath, "utf-8");

  css = css.replace(/url\(["']?([^"')]+)["']?\)/g, (_match, filePath) => {
    const fullPath = path.resolve(path.join(faRoot, "css"), filePath);
    if (!fs.existsSync(fullPath)) return _match;

    const ext = path.extname(filePath).toLowerCase();
    const mime =
      ext === ".woff2" ? "font/woff2" :
      ext === ".woff"  ? "font/woff"  :
      ext === ".ttf"   ? "font/ttf"   :
      ext === ".svg"   ? "image/svg+xml" : "application/octet-stream";

    const data = fs.readFileSync(fullPath).toString("base64");
    return `url(data:${mime};base64,${data})`;
  });

  return css;
}
